head.script:


							var OldRoles=null;
								var RolesKey=null;
								var Roles=[




								,



							];


							var OldEstructuras=null;
								var EstructurasRoots=null;
								var ExpandEstructuras=new Array();
								var Estructuras=[




								,



							];


							//						      
function DrawDIV(className, style, innerHTML)
{
 	var retval="";

	retval+='(#CHAR.LT#)div class="'+className+'" style="'+style+'" (#CHAR.GT#)';
	retval+=innerHTML;
	retval+='(#CHAR.LT#)/div(#CHAR.GT#)';

	return retval;
}

function DrawBUTTON(className, style, title, onClick)
{
  return '(#CHAR.LT#)button type="button" style="'+style+'" onclick="'+onClick+'" title="'+title+'" class="'+className+'" (#CHAR.GT#) (#CHAR.LT#)/button(#CHAR.GT#)'
}

function Expand(MyID)								            
{                     
	ExpandEstructuras["KEY"+MyID]=1;
	RefreshEstructuras();
}

function ExpandContract(MyID)								            
{              
	if (ExpandEstructuras["KEY"+MyID])
	{
		ExpandEstructuras["KEY"+MyID]=null;
	} else
	{
		ExpandEstructuras["KEY"+MyID]=1;
	}

	RefreshEstructuras();
}

function ExpandRoles()
{
	var reference=document.getElementById("ROLES");	
	if (reference.className=="DIV_REFERENCE CON")
		reference.className="DIV_REFERENCE EXP";
	else
		reference.className="DIV_REFERENCE CON";
}

function RolesContexMenu(MyID,event)
{
	var t;
	for (t=0; t!=Roles.length; t++)
		if (Roles[t].id==MyID)
		{
			parent.RolesContexMenu(Roles[t].id,Roles[t].COD,event, window);
			return;
		}
}

function EstructuraContexMenu(MyID,event)
{
	var t;
	for (t=0; t!=Estructuras.length; t++)
		if (Estructuras[t].id==MyID)
		{
			parent.EstructContexMenu(Estructuras[t].id,Estructuras[t].COD,event,window);
			return;
		}
}           

function NewEstructuraContexMenu(MyID,MyORDER,event)
{
	var t;

	for (t=0; t!=Estructuras.length; t++)
		if (Estructuras[t].id==MyID)
		{
			parent.NewEstructContexMenu(Estructuras[t].COD,MyORDER,event,window);
			return;
		}                            

	parent.NewEstructContexMenu("0",MyORDER,event,window);
}           

function ShowPersonas(MyID)
{            
	parent.ShowPersonas(MyID);
}



function RefreshRoles()
{   
	var t,d,f,rol,roles, row, cell, CNT,d;

	RolesKey=new Array();

	//obtengo la tabla de roles
	roles=document.getElementById("ROLES_TABLE");	
	for (t=0; t!=Roles.length; t++)
	{
		//Busco el ROL
		row=document.getElementById("ROL_"+Roles[t].id);	
		if (row) 
		{
			while(row.cells.length!=0)
				row.deleteCell(0);
		} else
		{
			//Agrego el ROL
			row=roles.insertRow(-1);	
			row.id="ROL_"+Roles[t].id;   
		}   

		CNT=0;
		for (d=0; d!=Estructuras.length; d++)
			if (Estructuras[d].ROL==Roles[t].COD) CNT++;


		cell=row.insertCell(-1);
		cell.className="GRP "+(Roles[t].COD=="OWNER"?"OWN":(Roles[t].UNQ?"UNQ":"MUL"));
		cell.innerHTML=DrawBUTTON("EDIT", "", "Mostrar el Menu", "RolesContexMenu("+Roles[t].id+",event);");
		cell.style.backgroundColor="#"+Roles[t].COL;

		cell=row.insertCell(-1);
		cell.className="DES";
		cell.innerHTML=Roles[t].DES;

		cell=row.insertCell(-1);
		cell.className="EST";


		if (CNT(#CHAR.GT#)2) CNT=2;           

		if (Roles[t].COD!="OWNER")
			switch(CNT+"-"+Roles[t].UNQ)
			{
				case "1-1": //Unico una VEZ
				case "1-0": //No Unico una VEZ
				case "2-0": //No Unico mas de una VEZ
					cell.innerHTML='(#CHAR.LT#)img src="Skins/_Default/Images/Workflow/Logs/OK.gif" width="16px" height="16px" /(#CHAR.GT#)'; 
					break;

				case "0-1": //Unico sin USAR
				case "0-0": //NO Unico sin USAR
					cell.innerHTML='(#CHAR.LT#)img src="Skins/_Default/Images/Workflow/Logs/WRN.gif" width="16px" height="16px" title="El Rol/Actor no esta definido en ningun NODO" /(#CHAR.GT#)'; 
					break;

				case "2-1": //Unico mas de una VEZ
					cell.innerHTML='(#CHAR.LT#)img src="Skins/_Default/Images/Workflow/Logs/ERR.gif" width="16px" height="16px" title="El Rol/Actor esta definido en mas de un NODO y no esta permitido para este tipo de Rol/Actor" /(#CHAR.GT#)'; 
					break;

				default:
					cell.innerHTML=CNT+"-"+Roles[t].UNQ;
					break;
			}



		//Agrego el ROL a la lista
		RolesKey[Roles[t].COD]=Roles[t];
	}   


	//Elimino los ROLES
	if (OldRoles)
	for (t=0; t!=OldRoles.length; t++)
	{  
		//Busco que el rol viejo
		f=false;           
		for (d=0; d!=Roles.length; d++)	if (Roles[d].id==OldRoles[t].id) f=true;

		if (!f)
		{
			//Busco el ROL
			row=document.getElementById("ROL_"+OldRoles[t].id);	

			//Elimino el Row
			roles.deleteRow(row.rowIndex);
		}
	}

}       

function CalcEstructuras(parentName, EstructurasRoots, Level)
{
	var t, estr, retval, child;

	//Inicio la estructura	
	retval={Width:0, Height:0};

	if (Estructuras.length!=0)
	for (t=0; t!=Estructuras.length; t++)
	{
		estr=Estructuras[t];	            
		estr.Level=Level;

		//Tengo que analizarla?
		if (estr.PAD!=parentName) continue;

		//Agrego la Estructura
		EstructurasRoots.push(estr);

		//Ccalculo los HIJOS
		estr.Childs=new Array();
		child=CalcEstructuras(estr.COD, estr.Childs, Level+1);

		//Hacer algo si no esta expandida			                                      
		if (ExpandEstructuras["KEY"+estr.id] || estr.Childs.length==0 || estr.ROL=="*")
		{
			//Ancho de esta columna                                     
			estr.Width=(child.Width==0?200:child.Width);     
			estr.Expand=true;                     

			//Agrego la Estructura Expandida
			ExpandEstructuras["KEY"+estr.id]=1;
		} else
		{
			//Ancho de esta columna                                     
			estr.Width=200;  
			estr.Expand=false;   
		}                    


		//Alto de esta columna                                     
		estr.Height     =100;
		estr.ChildHeight=child.Height;

		//sumo la salida
		retval.Width+=estr.Width;
		retval.Height=(estr.Height+estr.ChildHeight(#CHAR.GT#)retval.Height?estr.Height+estr.ChildHeight:retval.Height);
	}	

	return retval;
}     

function ResfreshEstructuraAddCommon(estr)
{
	var t, pos, ord;
	var retval=""; 
  if (estr.Childs.length==0)
  {       
 		if (estr.PAD)
 		{             
			retval+=DrawDIV("LINE_VERT ADD","top:0px;left:"+Math.round(estr.Width/2)+"px;","");
			retval+=DrawBUTTON("ADD", "left:"+Math.round(estr.Width/2 - 7)+"px;top:10px;", "Mostrar el Menu", "NewEstructuraContexMenu("+estr.id+",65536,event);")
 		} else
 		{
			retval+=DrawDIV("LINE_VERT","top:0px;left:"+Math.round(estr.Width/2)+"px;","");
			retval+=DrawBUTTON("ADD", "display:block;left:"+Math.round(estr.Width/2 - 7)+"px;top:10px;", "Mostrar el Menu", "NewEstructuraContexMenu("+estr.id+",65536,event);")
  	}
  } else
  {        
  	if (estr.Childs.length!=1) 
  	{
  		pos=0;

	  	for (t=1; t!=estr.Childs.length; t++)
	  	{     
	  		left =pos+Math.round(estr.Childs[t-1].Width/2);
	  		left+=pos+estr.Childs[t-1].Width+Math.round(estr.Childs[t].Width/2);
	  		left =Math.round(left / 2);

	  		ord  =Math.round((estr.Childs[t-1].ORD + estr.Childs[t].ORD) / 2);

				retval+=DrawDIV("LINE_VERT ADD","top:15px;left:"+left+"px;","");
				retval+=DrawBUTTON("ADD", "left:"+Math.round(left - 7)+"px;top:25px;", "Mostrar el Menu", "NewEstructuraContexMenu("+estr.id+","+ord+",event);")

				pos+=estr.Childs[t-1].Width;
	  	}      
  	}

	  //Primero
	  ord=Math.round(estr.Childs[0].ORD / 2);
	  retval+=DrawDIV("LINE_HORZ ADD","top:15px;left:0px;width:"+Math.round(estr.Childs[0].Width/2)+"px","");
		retval+=DrawDIV("LINE_VERT ADD","top:15px;left:0px;","");
		retval+=DrawBUTTON("ADD", "left:-7px;top:25px;", "Mostrar el Menu", "NewEstructuraContexMenu("+estr.id+","+ord+",event);")

	  //Ultimo
	  ord=estr.Childs[estr.Childs.length-1].ORD + 65536;
	  retval+=DrawDIV("LINE_HORZ ADD","top:15px;left:"+(estr.Width-Math.round(estr.Childs[estr.Childs.length-1].Width/2))+"px;width:"+Math.round(estr.Childs[estr.Childs.length-1].Width/2)+"px","");
		retval+=DrawDIV("LINE_VERT ADD","top:15px;left:"+estr.Width+"px;","");
		retval+=DrawBUTTON("ADD", "left:"+(estr.Width-7)+"px;top:25px;", "Mostrar el Menu", "NewEstructuraContexMenu("+estr.id+","+ord+",event);")
  }        

  return retval;
}

function RefreshEstructuraAddRoot(estr)
{ 
	return DrawDIV("ESTR_ADD_ROOT","width:"+estr.Width+"px;",ResfreshEstructuraAddCommon(estr));
}

function RefreshEstructuraAdd(estr)
{          
  return DrawDIV("ESTR_ADD","width:"+estr.Width+"px;",ResfreshEstructuraAddCommon(estr));
}

function RefreshEstructuraShow(estr)
{                
 	var retval="",left,width,color,label;

 	if (estr.PAD!="0")
 		retval+=DrawDIV("LINE_VERT","top:-15px;left:"+Math.round(estr.Width/2)+"px;","");


	if (estr.Expand)
	{
	  if (estr.Childs.length!=0)
	  {
			retval+=DrawDIV("LINE_VERT","top:70px;left:"+Math.round(estr.Width/2)+"px;","");

			if (estr.Childs.length!=1)
			{                                        
				left  =Math.round(estr.Childs[0].Width/2);

				width =estr.Width-left;
				width-=Math.round(estr.Childs[estr.Childs.length-1].Width/2);                   

				retval+=DrawDIV("LINE_HORZ","top:85px;width:"+width+"px;left:"+left+"px;","");
			}
		}         

		retval+=RefreshEstructuraAdd(estr);
	} else
	{
	  if (estr.Childs.length!=0)
	  {
			retval+=DrawDIV("LINE_VERT","top:70px;left:"+Math.round(estr.Width/2)+"px;","");
			retval+=DrawBUTTON("EXPAND", "left:"+(Math.round(estr.Width/2)-7)+"px;top:85px;", "Expandir el NODO", "Expand("+estr.id+");")
		}         
	}


 	if (estr.ROL=="*")
 	{                 
 		retval+=DrawDIV("LINE_VERT","top:0px;height:70px;left:"+Math.round(estr.Width/2)+"px;","");
 	} else
 	{                
 		label=""; 
 		color="FFF";
 		if (RolesKey[estr.ROL]) 
 		{
 			color=RolesKey[estr.ROL].COL;
 			if (RolesKey[estr.ROL].UNQ==0) label+=DrawDIV("TEXT", "", RolesKey[estr.ROL].DES);
 		}
 		label+=DrawDIV("TEXT BOLD", "", estr.DES);

 		switch(estr.CNT)
 		{
 			case 0:
 				break;

 			case 1:
 				label+=DrawDIV("TEXT", "", estr.ETT);
 				break;

 			default:
 				label+=DrawDIV("TEXT", "", estr.CNT+" Personas "+DrawBUTTON("SHOW", "", "Mostrar las Personas", "ShowPersonas("+estr.id+");") );
 		}

		retval+=DrawDIV("ESTR_SHOW"+(EstructuraSelect==estr.id?(EstructuraCopy?" COPY":" CUT"):""),"background-color:#"+color+";",
						 label+
						 DrawBUTTON("EDIT", "", "Mostrar el Menu", "EstructuraContexMenu("+estr.id+",event);")
						);
	}

	return retval;                   
}     

function RefreshEstructuraChild(EstructList)
{                  
	var t, estr, retval, pos;

	retval=""; pos=0;

	if (EstructList.length!=0)
	for (t=0; t!=EstructList.length; t++)
	{
		estr=EstructList[t];	

		if (estr.Expand)
		{
			//Agrego la Celda
			retval+=DrawDIV
							("ESTR_COL", 
							 "left:"+pos+"px;width:"+estr.Width+"px;height:"+(estr.Height+estr.ChildHeight)+"px;", 
										DrawDIV
										("ESTR_CHILD", 
										 "width:"+estr.Width+"px;height:"+estr.Height+"px;", 
										 RefreshEstructuraShow(estr)
										)+
										DrawDIV
										("ESTR_CHILD", 
										 "width:"+estr.Width+"px;height:"+estr.ChildHeight+"px;", 
										 RefreshEstructuraChild(estr.Childs)
										)
							); 
		} else
		{
			//Agrego la Celda
			retval+=DrawDIV
							("ESTR_COL", 
							 "left:"+pos+"px;width:"+estr.Width+"px;height:"+(estr.Height+estr.ChildHeight)+"px;", 
										DrawDIV
										("ESTR_CHILD", 
										 "width:"+estr.Width+"px;height:"+estr.Height+"px;", 
										 RefreshEstructuraShow(estr)
										)
							); 
		}


		pos+=estr.Width;
	}	

	return retval;
}


function RefreshEstructuras()
{
	var child;

	EstructurasRoots=new Array();

	//Calulo los Tamanos
	child=CalcEstructuras("0", EstructurasRoots, 0);
	child.Childs=EstructurasRoots;
	if (child.Width==0) child.Width=200;
	if (child.Height==0) child.Height=100;

	//Actualizo el Documento             
	document.getElementById("ORGANIGRAMA").innerHTML=DrawDIV("MARGIN_TOP","",RefreshEstructuraAddRoot(child))+DrawDIV("ESTR_ROOT", "width:"+child.Width+"px;height:"+child.Height+"px;", RefreshEstructuraChild(child.Childs));	
}

function Refresh(XML, select, copy)
{                   
	if (XML)
	{ 
		OldRoles=Roles;
		Roles=new Array();
		for (cur=XML.FindElement("ROLES").FirstChild(); cur!=null; cur=cur.Next())
			Roles.push( {id:cur.GetAttrInt("id"), COD:cur.GetAttr("COD"), DES:cur.GetAttr("DES"), COL:cur.GetAttr("COL"), UNQ: cur.GetAttr("UNQ") } );

		OldEstructuras=Estructuras;
		Estructuras=new Array();
		for (cur=XML.FindElement("ESTRUCTURAS").FirstChild(); cur!=null; cur=cur.Next())
			Estructuras.push( {id:cur.GetAttrInt("id"), COD:cur.GetAttr("COD"), DES:cur.GetAttr("DES"), ETT:cur.GetAttr("ETT"), PAD:cur.GetAttr("PAD"), ROL:cur.GetAttr("ROL"), ORD:cur.GetAttrInt("ORD"), CNT: cur.GetAttrInt("CNT"), INI: cur.GetAttrInt("INI") } );
	}

	if (select)
	{
		EstructuraSelect=select;
		EstructuraCopy=copy;
	} else
	{
		EstructuraSelect=0;
		EstructuraCopy=true;
	}

	RefreshRoles();
	RefreshEstructuras();
}

function OnLoad()
{     
	var t,l,c;
	var roots;
	var countLevel=new Array();

	//Analiso los Niveles
	EstructurasRoots=new Array();
	roots=CalcEstructuras("0", EstructurasRoots, 0);

	//Calcula la cantidad por niveles
	for (t=0; t!=Estructuras.length; t++)
	{
		if (countLevel[Estructuras[t].Level])
			countLevel[Estructuras[t].Level]++;
		else
			countLevel[Estructuras[t].Level]=1;
	}

	//Busco cual expandir
	for (l=0,c=0; l!=countLevel.length; l++)
	{
		c+=countLevel[l];
		if (c(#CHAR.GT#)20) break;
	}                           

	//Marco los Expandidos	
	for (t=0; t!=Estructuras.length; t++)
		if (Estructuras[t].Level(#CHAR.LT#)l)
			ExpandEstructuras["KEY"+Estructuras[t].id]=1;


	Refresh(null,0,true);
}

						//
